using TranSmart.Core.Result;
using TranSmart.Data;
using TranSmart.Data.Paging;
using TranSmart.Domain.Entities.Leave;
using TranSmart.Domain.Models;
using Microsoft.EntityFrameworkCore;
using System.Collections.Generic;
using System;
using System.Linq;
using System.Threading.Tasks;

namespace TranSmart.Service.Leave
{
    public partial interface ILeaveSettingsService : IBaseService<LeaveSettings>
    {

    }

    public partial class LeaveSettingsService : BaseService<LeaveSettings>, ILeaveSettingsService
    {
        public LeaveSettingsService(IUnitOfWork uow) : base(uow)
        {

        }

        public override async Task<LeaveSettings> GetById(Guid id)
        {
            return await UOW.GetRepositoryAsync<LeaveSettings>().SingleAsync(
                predicate: x => x.ID == id,
                include: i => i.Include(x => x.CompCreditTo).Include(x => x.CompoLeaveType),
                orderBy: o => o.OrderByDescending(x => x.AddedAt));
        }

        public override async Task<IPaginate<LeaveSettings>> GetPaginate(BaseSearch search)
        {
            return await UOW.GetRepositoryAsync<LeaveSettings>().GetPageListAsync(
                predicate: x => (string.IsNullOrEmpty(search.Name)
                     || x.CompCreditTo.Name.Contains(search.Name)
                     || x.CompoLeaveType.Name.Contains(search.Name)),
                include: i => i.Include(x => x.CompCreditTo).Include(x => x.CompoLeaveType),
                index: search.Page, size: search.Size, sortBy: search.SortBy ?? "HourCalculation", ascending: !search.IsDescend);
        }
    }
}
